// vaapi_transcode.c - تحويل ترميز فيديو عبر VAAPI
#include <libavcodec/avcodec.h>
#include <libavformat/avformat.h>
#include <stdio.h>

int main(int argc, char **argv) {
    const char *filename = argc > 1 ? argv[1] : "input.mp4";
    AVFormatContext *fmt_ctx = NULL;
    AVCodecContext *dec_ctx = NULL;
    AVCodecContext *enc_ctx = NULL;
    AVFrame *frame = av_frame_alloc();
    AVPacket *pkt = av_packet_alloc();

    avformat_open_input(&fmt_ctx, filename, NULL, NULL);
    avformat_find_stream_info(fmt_ctx, NULL);

    int stream_idx = av_find_best_stream(fmt_ctx, AVMEDIA_TYPE_VIDEO, -1, -1, 0, NULL);
    const AVCodec *dec_codec = avcodec_find_decoder(fmt_ctx->streams[stream_idx]->codecpar->codec_id);
    dec_ctx = avcodec_alloc_context3(dec_codec);
    avcodec_parameters_to_context(dec_ctx, fmt_ctx->streams[stream_idx]->codecpar);
    avcodec_open2(dec_ctx, dec_codec, NULL);

    const AVCodec *enc_codec = avcodec_find_encoder_by_name("h264_vaapi");
    enc_ctx = avcodec_alloc_context3(enc_codec);
    avcodec_parameters_to_context(enc_ctx, fmt_ctx->streams[stream_idx]->codecpar);
    avcodec_open2(enc_ctx, enc_codec, NULL);

    while (av_read_frame(fmt_ctx, pkt) >= 0) {
        if (pkt->stream_index == stream_idx) {
            avcodec_send_packet(dec_ctx, pkt);
            while (avcodec_receive_frame(dec_ctx, frame) >= 0) {
                avcodec_send_frame(enc_ctx, frame);
                while (avcodec_receive_frame(enc_ctx, frame) >= 0) {
                    printf("encoded\n");
                }
            }
        }
        av_packet_unref(pkt);
    }

    av_frame_free(&frame);
    av_packet_free(&pkt);
    avcodec_free_context(&dec_ctx);
    avcodec_free_context(&enc_ctx);
    avformat_close_input(&fmt_ctx);
    return 0;
}

